form:Form.form:Scripts:
		
function validar_clave()
{
	if(Ctrl('altaweb').GetCValue()=='1')
	{
		if (Ctrl('d_clave').GetCValue() == "" || Ctrl('d_clave2').GetCValue() == "")
		{
			alert('La clave actual y la clave nueva son requeridas');
			return false;		
		}
		if (Ctrl('d_clave').GetCValue() != Ctrl('d_clave2').GetCValue())
		{
			alert('Las claves no concuerdan');
			return false;
		}
		return true;
	}
	else 
	{
		if (Ctrl('d_clave').GetCValue() == "" || Ctrl('d_clave2').GetCValue() == "")
		{
			alert('La clave nueva es requerida');
			return false;		
		}
		if (Ctrl('d_clave').GetCValue() != Ctrl('d_clave2').GetCValue())
		{
			alert('Las claves no concuerdan');
			return false;
		}
		return true;
	}
}
